import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faCat } from '@awesome.me/kit-KIT_CODE/icons/sharp/solid'


function Side(){


    return (
        <div className="side-bar col">
            <div className="settings-container row">
                <FontAwesomeIcon icon={faCat} />
            </div>
            <div className="userPicture-container row">
                2 of 2
            </div>
        </div>
    )

}

export default Side;
